286	/// Force-break a stuck lock
287	fn run_unlock() -> i32 {
288	    use std::process::Command;
289	
290	    // Check if lock exists
291	    let check = Command::new("git")
292	        .args(["show-ref", "--verify", "--quiet", LOCK_REF])
293	        .status();
294	
295	    match check {
296	        Ok(status) if status.success() => {
297	            // Lock exists, delete it
298	            let delete = Command::new("git")
299	                .args(["update-ref", "-d", LOCK_REF])
300	                .output();
301	
302	            match delete {
303	                Ok(output) if output.status.success() => {
304	                    eprintln!("unlock: lock broken successfully");
305	                    0
306	                }
307	                Ok(output) => {
308	                    eprintln!("unlock: error: failed to delete lock: {}",
309	                        String::from_utf8_lossy(&output.stderr));
310	                    1
